output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic Volume",
      "simple": "Choose the pelvic CT volume from the dropdown.",
      "detailed": "This CT scan is the primary input for all segmentation steps; selecting the correct volume ensures the algorithms operate on the right patient data. In the 'Input CT Volume' menu, pick the volume that contains the pelvis."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment Pelvis",
      "simple": "Click 'Run Step 1: Segment Pelvis' to create a 3D segmentation of the pelvic bone.",
      "detailed": "This step isolates the pelvic bone from surrounding soft tissues using an automatic segmentation algorithm. The resulting pelvic segmentation provides the anatomical reference for fracture analysis, reduction, and screw planning."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fractures",
      "simple": "Click 'Run Step 2: Segment Fractures' to detect and label individual fracture fragments.",
      "detailed": "The algorithm identifies all fracture fragments and creates separate segment labels for each. These labeled fragments will be used in subsequent steps for reduction and screw planning."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Fragments",
      "simple": "Untick any fragments you wish to exclude from the planning process.",
      "detailed": "You can remove small, irrelevant, or hardware-affected fragments so they do not interfere with reduction or screw planning. Untick each segment in the list that should be ignored."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Template",
      "simple": "Click 'Run Step 3: Generate Template' to create an intact pelvic shape model.",
      "detailed": "Using the segmented pelvis, a statistical shape model fits an intact template that represents the uninjured anatomy. This template serves as the target alignment for reducing fracture fragments."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register & Reduce",
      "simple": "Click 'Run Step 4: Register _Reduce' to automatically align and reduce the fracture fragments to the template.",
      "detailed": "The fragments are registered to the intact pelvic template and repositioned to restore normal anatomy. The output is a unified reduced segmentation that combines all fragments in their correct positions."
    },
    {
      "step_id": "cb_step_7",
      "title": "Manually Adjust Fragment?",
      "simple": "If the automatic reduction needs refinement, check 'Manually adjust a fragment'. Otherwise, leave unchecked and click Done.",
      "detailed": "This step gives you the option to fine-tune the position of individual fragments. If the reduction looks satisfactory, skip to screw planning. If a fragment is misaligned, proceed to adjust it manually."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment",
      "simple": "In the 'Fragment' dropdown, choose the fragment you want to adjust.",
      "detailed": "Select the specific fragment from the list—its name corresponds to one of the fracture segments identified earlier. This will allow you to apply positional and rotational transforms to only that fragment."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Pose",
      "simple": "Use the transform controls to adjust the position and rotation of the selected fragment.",
      "detailed": "Manipulate the fragment's location and orientation in 3D to better align it with the template. This manual correction refines the reduction quality before you apply the changes."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Adjustments",
      "simple": "Click 'Apply adjustments' to commit the manual changes into the reduction segmentation.",
      "detailed": "Saves the adjusted fragment position, making it permanent for screw planning. After this step, the reduction segmentation is updated."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screws",
      "simple": "Click 'Run Step 5: Plan Screws' to generate suggested screw trajectories.",
      "detailed": "The algorithm automatically proposes safe screw paths based on the reduced bone anatomy, accounting for bone corridors and avoiding fracture lines. These trajectories can be reviewed and edited next."
    },
    {
      "step_id": "cb_step_12",
      "title": "Edit Screw Trajectories?",
      "simple": "If you need to modify any screw trajectory, check 'Edit Screw trajectories'. Otherwise, leave unchecked and finish.",
      "detailed": "You can manually adjust the position and orientation of the suggested screws to improve surgical feasibility. If all trajectories are acceptable, the planning is complete."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Trajectories",
      "simple": "Use the transform controls to adjust the position and rotation of the screw trajectories.",
      "detailed": "Fine-tune each screw's path to align with your preferred entry point and target, ensuring optimal fixation strength and safety. Visual feedback helps verify placement."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws",
      "simple": "Click 'Regenerate screws from edited lines' to update the screw models based on your changes.",
      "detailed": "This converts the adjusted trajectory lines into final screw models, ready for visualization and surgical planning documentation."
    },
    {
      "step_id": "cb_step_15",
      "title": "Disable Edit Mode",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to exit adjustment mode.",
      "detailed": "This final step locks in your adjustments and returns you to the main interface. Your screw plan is now complete."
    }
  ]
}
